#!/usr/bin/env python3
"""
serial_odom_node.py — ROS2 Jazzy
Lee ODOM del Arduino y publica:
  - /odom  (nav_msgs/Odometry)
  - TF odom -> base_link

Formato Arduino:
  ODOM,x,y,theta,encL,encR,pwmL,pwmR

CORRECCIONES respecto a versión anterior:
  - Twist calculado en m/s real (no RPM)
  - Velocidad lineal y angular calculadas desde encoders
  - Lectura serial en hilo separado -> timer no se bloquea
  - Covarianzas razonables para slam_toolbox
"""

import math
import serial
import threading
import time

import rclpy
from rclpy.node import Node
from nav_msgs.msg import Odometry
from geometry_msgs.msg import Quaternion, TransformStamped
from tf2_ros import TransformBroadcaster

# ── Parámetros físicos (deben coincidir con el Arduino) ──────────────
PULSOS_POR_VUELTA = 1420.0 * 4.0   # 4x por CHANGE en ISR
RADIO_RUEDA       = 0.03            # metros
BASE_RUEDAS       = 0.34            # metros
LOOP_S            = 0.05            # período del Arduino (50ms)


class SerialOdomNode(Node):

    def __init__(self):
        super().__init__('serial_odom_node')

        self.declare_parameter('port',        '/dev/ttyACM0')
        self.declare_parameter('baud',        115200)
        self.declare_parameter('frame_id',    'odom')
        self.declare_parameter('child_frame', 'base_link')

        port         = self.get_parameter('port').value
        baud         = self.get_parameter('baud').value
        self.frame_id    = self.get_parameter('frame_id').value
        self.child_frame = self.get_parameter('child_frame').value

        # ── Serial ──────────────────────────────────────────────────
        self._ser      = serial.Serial(port, baud, timeout=0.1)
        self._ser_lock = threading.Lock()
        time.sleep(2.5)
        self._ser.reset_input_buffer()

        # ── Estado odometría ────────────────────────────────────────
        self._x     = 0.0
        self._y     = 0.0
        self._theta = 0.0
        self._vx    = 0.0   # m/s
        self._wz    = 0.0   # rad/s

        self._prev_encL = None
        self._prev_encR = None
        self._data_lock = threading.Lock()

        # ── ROS2 ────────────────────────────────────────────────────
        self.odom_pub      = self.create_publisher(Odometry, '/odom', 10)
        self.tf_broadcaster = TransformBroadcaster(self)

        # Hilo lector serial (no bloquea el executor)
        threading.Thread(target=self._reader_worker, daemon=True).start()

        # Timer publicador a 20 Hz
        self.create_timer(0.05, self._publish_odom)

        self.get_logger().info(f'serial_odom_node listo en {port} @ {baud}')

    # ────────────────────────────────────────────────────────────────
    # Hilo lector: parsea ODOM y actualiza estado
    # ────────────────────────────────────────────────────────────────
    def _reader_worker(self):
        while True:
            try:
                with self._ser_lock:
                    line = self._ser.readline()

                line = line.decode('utf-8', errors='ignore').strip()
                if not line.startswith('ODOM,'):
                    continue

                parts = line.split(',')
                if len(parts) < 8:
                    continue

                x     = float(parts[1])
                y     = float(parts[2])
                theta = float(parts[3])
                encL  = int(parts[4])
                encR  = int(parts[5])
                # pwmL = int(parts[6])  # no usado aquí
                # pwmR = int(parts[7])

                # ── Velocidades desde encoders ──────────────────────
                with self._data_lock:
                    if self._prev_encL is not None:
                        dL = encL - self._prev_encL
                        dR = encR - self._prev_encR

                        distL = (2.0 * math.pi * RADIO_RUEDA * dL) / PULSOS_POR_VUELTA
                        distR = (2.0 * math.pi * RADIO_RUEDA * dR) / PULSOS_POR_VUELTA

                        vx = ((distL + distR) / 2.0) / LOOP_S
                        wz = ((distR - distL) / BASE_RUEDAS) / LOOP_S

                        self._vx = vx
                        self._wz = wz

                    self._prev_encL = encL
                    self._prev_encR = encR
                    self._x     = x
                    self._y     = y
                    self._theta = theta

            except Exception as e:
                self.get_logger().warn(f'Error serial: {e}')
                time.sleep(0.1)

    # ────────────────────────────────────────────────────────────────
    # Timer: publica /odom y TF
    # ────────────────────────────────────────────────────────────────
    def _publish_odom(self):
        with self._data_lock:
            x     = self._x
            y     = self._y
            theta = self._theta
            vx    = self._vx
            wz    = self._wz

        now = self.get_clock().now().to_msg()

        qz = math.sin(theta / 2.0)
        qw = math.cos(theta / 2.0)

        # ── /odom ───────────────────────────────────────────────────
        odom = Odometry()
        odom.header.stamp    = now
        odom.header.frame_id = self.frame_id
        odom.child_frame_id  = self.child_frame

        odom.pose.pose.position.x  = x
        odom.pose.pose.position.y  = y
        odom.pose.pose.position.z  = 0.0
        odom.pose.pose.orientation.x = 0.0
        odom.pose.pose.orientation.y = 0.0
        odom.pose.pose.orientation.z = qz
        odom.pose.pose.orientation.w = qw

        # Covarianza pose (diagonal)
        odom.pose.covariance[0]  = 0.05   # xx
        odom.pose.covariance[7]  = 0.05   # yy
        odom.pose.covariance[35] = 0.1    # yaw

        odom.twist.twist.linear.x  = vx
        odom.twist.twist.angular.z = wz

        # Covarianza twist
        odom.twist.covariance[0]  = 0.05
        odom.twist.covariance[7]  = 0.05
        odom.twist.covariance[35] = 0.1

        self.odom_pub.publish(odom)

        # ── TF odom -> base_link ─────────────────────────────────────
        t = TransformStamped()
        t.header.stamp    = now
        t.header.frame_id = self.frame_id
        t.child_frame_id  = self.child_frame

        t.transform.translation.x = x
        t.transform.translation.y = y
        t.transform.translation.z = 0.0
        t.transform.rotation.x = 0.0
        t.transform.rotation.y = 0.0
        t.transform.rotation.z = qz
        t.transform.rotation.w = qw

        self.tf_broadcaster.sendTransform(t)


def main(args=None):
    rclpy.init(args=args)
    node = SerialOdomNode()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    node.destroy_node()
    rclpy.shutdown()


if __name__ == '__main__':
    main()
